var p = msg.payload;

// Temperature thresholds (degC)
var TEMP_WARNING  = 65;   // above this = WARNING
var TEMP_ALARM    = 80;   // above this = ALARM (motor in danger)
var RATE_WARNING  = 0.5;  // rising faster than 0.5 degC/s = WARNING

// Determine alarm state
if (p.temperature >= TEMP_ALARM || p.anomaly_flag === 1) {
    p.alarm_state = "ALARM";
} else if (p.temperature >= TEMP_WARNING || p.temp_rate >= RATE_WARNING) {
    p.alarm_state = "WARNING";
} else {
    p.alarm_state = "NORMAL";
}

// Add human-readable status
p.status_message = "Motor " + p.motor_id + 
    " | Temp: " + p.temperature + "C" +
    " | State: " + p.alarm_state;

msg.payload = p;
return msg;
